    41|interface AuthContextType {
    42|  user: User | null
    43|  login: (email: string, password: [REDACTED] => Promise<{ ok: boolean; error?: string }>
    44|  register: (name: string, email: string, password: [REDACTED] phone: string) => Promise<{ ok: boolean; error?: string }>
    45|  logout: () => void
    46|  updateProfile: (data: Partial<User>) => Promise<{ ok: boolean; error?: string }>
    47|  changePassword: [REDACTED] string, newPass: string) => Promise<{ ok: boolean; error?: string }>
    48|  addresses: Address[]
    49|  addAddress: (a: Omit<Address, "id">) => Promise<{ ok: boolean; error?: string }>
    50|  updateAddress: (id: string, a: Partial<Address>) => Promise<{ ok: boolean; error?: string }>
    51|  removeAddress: (id: string) => Promise<void>
    52|  orders: Order[]
    53|  refreshOrders: () => Promise<void>
