    59|
    60|const AuthContext = createContext<AuthContextType | null>(null)
    61|
    62|async function api(path: string, options?: RequestInit) {
    63|  const token = typeof window !== "undefined" ? localStorage.getItem("viajero_token") : null
    64|  const res = await fetch(path, {
    65|    ...options,
    66|    headers: {
