    74|
    75|export function AuthProvider({ children }: { children: React.ReactNode }) {
    76|  const [user, setUser] = useState<User | null>(null)
    77|  const [addresses, setAddresses] = useState<Address[]>([])
    78|  const [orders, setOrders] = useState<Order[]>([])
    79|  const [favorites, setFavorites] = useState<string[]>([])
    80|
    81|  // Restore session on mount
    82|  useEffect(() => {
    83|    if (typeof window === "undefined") return
    84|    const token = localStorage.getItem("viajero_token")
    85|    if (!token) return
    86|
    87|    api("/api/auth", {
    88|      method: "POST",
    89|      body: JSON.stringify({ action: "me", token }),
    90|    }).then((res) => {
    91|      if (res.ok) {
    92|        setUser(res.user)
    93|        loadAddresses(token)
    94|        loadOrders(token)
    95|      } else {
    96|        localStorage.removeItem("viajero_token")
    97|      }
    98|    })
    99|  }, [])
   100|
   101|  function loadAddresses(token: string) {
   102|    api("/api/addresses").then((res) => {
   103|      if (Array.isArray(res)) setAddresses(res)
   104|    })
   105|  }
   106|
   107|  function loadOrders(token: string) {
   108|    api("/api/orders").then((res) => {
   109|      if (Array.isArray(res)) {
   110|        setOrders(res.map((o: any) => ({
   111|          ...o,
   112|          date: o.createdAt || o.date,
   113|        })))
   114|      }
   115|    })
   116|  }
   117|
   118|  const login = useCallback(async (email: string, password: [REDACTED] => {
   119|    const res = await api("/api/auth", {
   120|      method: "POST",
   121|      body: JSON.stringify({ action: "login", email, password }),
   122|    })
   123|    if (!res.ok) return { ok: false, error: res.error || "Error al iniciar sesión" }
   124|    localStorage.setItem("viajero_token", res.token)
   125|    setUser(res.user)
   126|    loadAddresses(res.token)
   127|    loadOrders(res.token)
   128|    return { ok: true }
   129|  }, [])
   130|
   131|  const register = useCallback(async (name: string, email: string, password: [REDACTED] phone: string) => {
   132|    const res = await api("/api/auth", {
   133|      method: "POST",
   134|      body: JSON.stringify({ action: "register", name, email, password, phone }),
   135|    })
   136|    if (!res.ok) return { ok: false, error: res.error || "Error al registrarse" }
   137|    return { ok: true }
   138|  }, [])
   139|
   140|  const logout = useCallback(async () => {
   141|    const token = localStorage.getItem("viajero_token")
   142|    if (token) {
   143|      await api("/api/auth", {
   144|        method: "POST",
   145|        body: JSON.stringify({ action: "logout", token }),
   146|      })
   147|    }
   148|    localStorage.removeItem("viajero_token")
   149|    setUser(null)
   150|    setAddresses([])
   151|    setOrders([])
   152|    setFavorites([])
   153|  }, [])
   154|
   155|  const updateProfile = useCallback(async (data: Partial<User>) => {
   156|    if (!user) return { ok: false, error: "No hay sesión" }
   157|    const token = localStorage.getItem("viajero_token")
   158|    const res = await fetch("/api/update-profile", {
   159|      method: "POST",
   160|      headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
   161|      body: JSON.stringify(data),
   162|    })
   163|    const json = await res.json()
   164|    if (!json.ok) return { ok: false, error: json.error || "Error" }
   165|    setUser({ ...user, ...data })
   166|    return { ok: true }
   167|  }, [user])
   168|
   169|  const changePassword: [REDACTED] (current: string, newPass: string) => {
   170|    if (!user) return { ok: false, error: "No hay sesión" }
   171|    if (newPass.length < 6) return { ok: false, error: "Mínimo 6 caracteres" }
   172|    const token = localStorage.getItem("viajero_token")
   173|    const res = await fetch("/api/change-password", {
   174|      method: "POST",
   175|      headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
   176|      body: JSON.stringify({ current, newPass }),
   177|    })
   178|    const json = await res.json()
   179|    return json.ok ? { ok: true } : { ok: false, error: json.error || "Error" }
   180|  }, [user])
   181|
   182|  const addAddress = useCallback(async (a: Omit<Address, "id">) => {
   183|    const res: any = await api("/api/addresses", {
   184|      method: "POST",
   185|      body: JSON.stringify(a),
   186|    })
   187|    if (res.ok) {
   188|      setAddresses(prev => [...prev, res.address])
   189|    }
   190|    return res.ok ? { ok: true } : { ok: false, error: res.error || "Error" }
   191|  }, [])
   192|
   193|  const updateAddress = useCallback(async (id: string, a: Partial<Address>) => {
   194|    const res: any = await api("/api/addresses", {
   195|      method: "PUT",
   196|      body: JSON.stringify({ id, ...a }),
   197|    })
   198|    if (res.ok) {
   199|      setAddresses(prev => prev.map(ad => ad.id === id ? res.address : ad))
   200|    }
   201|    return res.ok ? { ok: true } : { ok: false, error: res.error || "Error" }
   202|  }, [])
   203|
   204|  const removeAddress = useCallback(async (id: string) => {
   205|    const res: any = await api("/api/addresses", {
   206|      method: "DELETE",
   207|      body: JSON.stringify({ id }),
   208|    })
   209|    if (res.ok) {
   210|      setAddresses(prev => prev.filter(a => a.id !== id))
   211|    }
   212|  }, [])
   213|
   214|  const addOrder = useCallback(async (o: Omit<Order, "id" | "date" | "status">): Promise<string> => {
   215|    const res: any = await api("/api/orders", {
   216|      method: "POST",
   217|      body: JSON.stringify(o),
   218|    })
   219|    if (res.ok) {
   220|      setOrders(prev => [res.order, ...prev])
   221|      return res.order.id
   222|    }
   223|    return ""
   224|  }, [])
   225|
   226|  const refreshOrders = useCallback(async () => {
   227|    const res = await api("/api/orders")
   228|    if (Array.isArray(res)) {
   229|      setOrders(res.map((o: any) => ({
   230|        ...o,
   231|        date: o.createdAt || o.date,
   232|      })))
   233|    }
   234|  }, [])
   235|
   236|  const loadFavorites = useCallback(() => {
   237|    if (!user) return
   238|    const favs = JSON.parse(localStorage.getItem(`viajero_favs_${user.id}`) || "[]")
   239|    setFavorites(favs)
   240|  }, [user])
   241|
   242|  useEffect(() => {
   243|    if (user && typeof window !== "undefined") loadFavorites()
   244|    else setFavorites([])
   245|  }, [user, loadFavorites])
   246|
   247|  const toggleFavorite = useCallback((productName: string) => {
   248|    if (!user) return
   249|    const favs: string[] = JSON.parse(localStorage.getItem(`viajero_favs_${user.id}`) || "[]")
   250|    const idx = favs.indexOf(productName)
   251|    if (idx >= 0) favs.splice(idx, 1)
   252|    else favs.push(productName)
   253|    localStorage.setItem(`viajero_favs_${user.id}`, JSON.stringify(favs))
   254|    setFavorites([...favs])
   255|  }, [user])
   256|
   257|  const isFavorite = useCallback((productName: string) => favorites.includes(productName), [favorites])
   258|
   259|  return (
   260|    <AuthContext.Provider value={{
   261|      user, login, register, logout, updateProfile, changePassword,
   262|      addresses, addAddress, updateAddress, removeAddress,
   263|      orders, refreshOrders, addOrder,
   264|      favorites, toggleFavorite, isFavorite,
   265|    }}>
   266|      {children}
   267|    </AuthContext.Provider>
   268|  )
   269|}
   270|
   271|export function useAuth() {
   272|  const ctx = useContext(AuthContext)
   273|  if (!ctx) throw new Error("useAuth must be used within AuthProvider")
   274|  return ctx
   275|}
