{"content": "     1|// Promo codes — serialized in localStorage so admin can add them
     2|export interface PromoCode {
     3|  code: string
     4|  type: "percentage" | "fixed"
     5|  value: number     // percentage (10) or fixed amount (15000)
     6|  minPurchase: number
     7|  maxUses: number
     8|  usedCount: number
     9|  expiresAt: number | null
    10|}
    11|
    12|const STORAGE_KEY = "viajero_promos"
    13|
    14|const DEFAULT_PROMOS: PromoCode[] = [
    15|  { code: "BIENVENIDO10", type: "percentage", value: 10, minPurchase: 100000, maxUses: 100, usedCount: 0, expiresAt: null },
    16|  { code: "ENVIOGRATIS", type: "fixed", value: 15000, minPurchase: 500000, maxUses: 50, usedCount: 0, expiresAt: null },
    17|]
    18|
    19|export function getPromoCodes(): PromoCode[] {
    20|  try {
    21|    const saved = localStorage.getItem(STORAGE_KEY)
    22|    if (saved) return JSON.parse(saved)
    23|  } catch {}
    24|  localStorage.setItem(STORAGE_KEY, JSON.stringify(DEFAULT_PROMOS))
    25|  return DEFAULT_PROMOS
    26|}
    27|
    28|export function validatePromo(code: string, cartTotal: number): { ok: boolean; error?: string; promo?: PromoCode } {
    29|  const promos = getPromoCodes()
    30|  const p = promos.find((x) => x.code.toUpperCase() === code.toUpperCase())
    31|  if (!p) return { ok: false, error: "Código inválido" }
    32|  if (p.expiresAt && p.expiresAt < Date.now()) return { ok: false, error: "Código expirado" }
    33|  if (p.usedCount >= p.maxUses) return { ok: false, error: "Código agotado" }
    34|  if (cartTotal < p.minPurchase) return { ok: false, error: `Mínimo Gs. ${p.minPurchase.toLocaleString("es-PY")}` }
    35|  return { ok: true, promo: p }
    36|}
    37|
    38|export function applyPromo(total: number, promo: PromoCode): number {
    39|  if (promo.type === "percentage") return total - (total * promo.value) / 100
    40|  return Math.max(0, total - promo.value)
    41|}
    42|
    43|export function usePromo(promo: PromoCode) {
    44|  const promos = getPromoCodes()
    45|  const idx = promos.findIndex((p) => p.code === promo.code)
    46|  if (idx >= 0) {
    47|    promos[idx].usedCount++
    48|    localStorage.setItem(STORAGE_KEY, JSON.stringify(promos))
    49|  }
    50|}
