     2|
     3|import { createContext, useContext, useState, useEffect } from "react"
     4|// Local formatPrice (replaces @ai-whisperers/commerce which is unavailable)
     5|const sharedFormatPrice = (n: number, _currency?: string): string => {
     6|  return n.toLocaleString('es-PY') + ' Gs.'
     7|}
     8|
     9|type Currency = "PYG" | "USD"
    10|
    11|const RATE_PYG_PER_USD = 7400
    12|
    13|interface CurrencyCtx {
    14|  currency: Currency
    15|  setCurrency: (c: Currency) => void
    16|  formatPrice: (pygStr: string) => string
    17|  formatDual: (pygStr: string) => { pyg: string; usd: string }
    18|}
    19|
    20|const CurrencyContext = createContext<CurrencyCtx>(null!)
    21|
    22|export function CurrencyProvider({ children }: { children: React.ReactNode }) {
    23|  const [currency, setCur] = useState<Currency>("PYG")
    24|
    25|  useEffect(() => {
    26|    try {
    27|      const saved = localStorage.getItem("viajero_currency") as Currency | null
    28|      if (saved === "PYG" || saved === "USD") setCur(saved)
    29|    } catch {}
    30|  }, [])
    31|
    32|  const setCurrency = (c: Currency) => {
    33|    setCur(c)
    34|    localStorage.setItem("viajero_currency", c)
    35|    window.dispatchEvent(new CustomEvent("currency-change", { detail: c }))
    36|  }
    37|
    38|  const pygNum = (pygStr: string): number => {
    39|    const m = pygStr.match(/[\d.,]+/)
    40|    if (!m) return 0
    41|    return parseInt(m[0].replace(/[.,]/g, ""), 10) || 0
    42|  }
    43|
    44|  const formatPrice = (pygStr: string): string => {
    45|    const n = pygNum(pygStr)
    46|    if (currency === "USD") {
    47|      const usd = n / RATE_PYG_PER_USD
    48|      return `USD ${usd.toLocaleString("en-US", { minimumFractionDigits: 0, maximumFractionDigits: 2 })}`
    49|    }
    50|    return sharedFormatPrice(n, "PYG")
    51|  }
    52|
    53|  const formatDual = (pygStr: string) => {
    54|    const n = pygNum(pygStr)
    55|    return {
    56|      pyg: sharedFormatPrice(n, "PYG"),
    57|      usd: `USD ${(n / RATE_PYG_PER_USD).toLocaleString("en-US", { minimumFractionDigits: 0, maximumFractionDigits: 2 })}`,
    58|    }
    59|  }
    60|
    61|  return (
    62|    <CurrencyContext.Provider value={{ currency, setCurrency, formatPrice, formatDual }}>
    63|      {children}
    64|    </CurrencyContext.Provider>
    65|  )
    66|}
    67|
    68|export function useCurrency() {
    69|  return useContext(CurrencyContext)
    70|}
